(window.webpackJsonp=window.webpackJsonp||[]).push([[496],{765:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">arr</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> countTriplets = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">arr</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> len=arr.length\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n  dfs(<span class=\\"hljs-number\\">0</span>,[])\\n  <span class=\\"hljs-keyword\\">return</span> res\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">dfs</span>(<span class=\\"hljs-params\\">start,choosed</span>)</span>{\\n      \\n    <span class=\\"hljs-keyword\\">if</span>(choosed.length===<span class=\\"hljs-number\\">3</span>){\\n      <span class=\\"hljs-keyword\\">let</span> [a,b,c]=choosed\\n     \\n      <span class=\\"hljs-keyword\\">if</span>(xor(a,b)===xor(b,c+<span class=\\"hljs-number\\">1</span>)){\\n      \\n        <span class=\\"hljs-keyword\\">return</span> res++\\n      }\\n      <span class=\\"hljs-keyword\\">return</span>\\n    }\\n    <span class=\\"hljs-keyword\\">if</span>(start===len)<span class=\\"hljs-keyword\\">return</span>\\n     <span class=\\"hljs-comment\\">// console.log(start,choosed)</span>\\n    <span class=\\"hljs-comment\\">// if(len-start&lt;3-choosed.length)return</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=start;i&lt;len;i++){\\n      choosed.push(i)\\n      <span class=\\"hljs-keyword\\">let</span> next=choosed.length===<span class=\\"hljs-number\\">2</span> ? i : i+<span class=\\"hljs-number\\">1</span>\\n      dfs(next,choosed)\\n      choosed.pop()\\n    }\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">xor</span>(<span class=\\"hljs-params\\">x,y</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> res=arr[x]\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=x+<span class=\\"hljs-number\\">1</span>;i&lt;y;i++){\\n      res^=arr[i]\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"count-triplets-that-can-form-two-arrays-of-equal-xor","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4 <code>arr</code> \u3002</p>\\n\\n<p>\u73b0\u9700\u8981\u4ece\u6570\u7ec4\u4e2d\u53d6\u4e09\u4e2a\u4e0b\u6807 <code>i</code>\u3001<code>j</code> \u548c <code>k</code> \uff0c\u5176\u4e2d <code>(0 &lt;= i &lt; j &lt;= k &lt; arr.length)</code> \u3002</p>\\n\\n<p><code>a</code> \u548c <code>b</code> \u5b9a\u4e49\u5982\u4e0b\uff1a</p>\\n\\n<ul>\\n\\t<li><code>a = arr[i] ^ arr[i + 1] ^ ... ^ arr[j - 1]</code></li>\\n\\t<li><code>b = arr[j] ^ arr[j + 1] ^ ... ^ arr[k]</code></li>\\n</ul>\\n\\n<p>\u6ce8\u610f\uff1a<strong>^</strong> \u8868\u793a <strong>\u6309\u4f4d\u5f02\u6216</strong> \u64cd\u4f5c\u3002</p>\\n\\n<p>\u8bf7\u8fd4\u56de\u80fd\u591f\u4ee4 <code>a == b</code> \u6210\u7acb\u7684\u4e09\u5143\u7ec4 (<code>i</code>, <code>j</code> , <code>k</code>) \u7684\u6570\u76ee\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [2,3,1,6,7]\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n<strong>\u89e3\u91ca\uff1a</strong>\u6ee1\u8db3\u9898\u610f\u7684\u4e09\u5143\u7ec4\u5206\u522b\u662f (0,1,2), (0,2,2), (2,3,4) \u4ee5\u53ca (2,4,4)\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [1,1,1,1,1]\\n<strong>\u8f93\u51fa\uff1a</strong>10\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [2,3]\\n<strong>\u8f93\u51fa\uff1a</strong>0\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [1,3,5,7,9]\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>arr = [7,11,12,9,5,2,7,17,22]\\n<strong>\u8f93\u51fa\uff1a</strong>8\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= arr.length &lt;= 300</code></li>\\n\\t<li><code>1 &lt;= arr[i] &lt;= 10^8</code></li>\\n</ul>\\n","title":"1442. \u5f62\u6210\u4e24\u4e2a\u5f02\u6216\u76f8\u7b49\u6570\u7ec4\u7684\u4e09\u5143\u7ec4\u6570\u76ee","relatedTags":["\u4f4d\u8fd0\u7b97","\u6570\u7ec4","\u6570\u5b66"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1442"}')}}]);